files.css:
body { font-family: system-ui, sans-serif; padding: 1.5rem; max-width: 38rem; line-height: 1.6; }
code { background: #f1f5f9; padding: 0.1rem 0.35rem; border-radius: 4px; font-size: 0.9em; }
li { margin: 0.35rem 0; }

body { font-family: sans-serif; padding: 1.5rem; }
button { margin-right: 0.5rem; padding: 0.45rem 0.85rem; cursor: pointer; }
#count { font-weight: bold; font-size: 100px; }

body { font-family: sans-serif; padding: 1.5rem; }
#box { width: 10rem; padding: 2rem; text-align: center; border: 2px solid #cbd5e1; border-radius: 8px; background: #f8fafc; cursor: pointer; transition: background 0.15s, border-color 0.15s; }
#status { color: #64748b; margin-bottom: 0.75rem; }

body { margin: 0; font-family: system-ui, sans-serif; }
.topnav { display: flex; align-items: center; gap: 1rem; padding: 0.75rem 1rem; background: #1e293b; color: #fff; }
.topnav a { color: #93c5fd; text-decoration: none; }
.menu-btn { padding: 0.35rem 0.65rem; cursor: pointer; }
.layout { display: grid; grid-template-columns: 160px 1fr; min-height: 140px; }
.sidebar { background: #dbeafe; padding: 1rem; transition: transform 0.2s; }
.sidebar a { display: block; color: #1e40af; text-decoration: none; margin-bottom: 0.5rem; }
main { padding: 1rem; }
@media (max-width: 520px) {
  .layout { grid-template-columns: 1fr; }
  .sidebar { position: absolute; left: 0; top: 48px; width: 180px; z-index: 10; transform: translateX(-100%); }
  .sidebar.open { transform: translateX(0); }
  main { margin-top: 0; }
}
